	public int getBoundedCount(int[] a, int[] b, int upperBound, int lowerBound) {
		Arrays.sort(a);
		Arrays.sort(b);
		int count = 0;
		for (int i = 0; i < a.length; i++) {
			for (int j = 0; j < b.length; j++) {
				int val = a[i] * a[i] + b[j] * b[j];
				if (val >= lowerBound) {
					if (val <= upperBound) {
						count++;
					} else {
						break;
					}
				}
			}
		}
		return count;
	}
